/**
 * Turn-local guard-fire + telemetry accumulator. Construct ONE per turn (createTurnTracker). It records guard fires, per-step round-trip + tool-call counts, individual tool results, and the timing buckets, then finalize() resolves every open fire via the pure derive fns and emits the events + the turn record. NO disk I/O — the caller hands finalize()'s output to the store module.
 */
// @kern-source: guard-telemetry:242
export class GuardTurnTracker {
  private engineId: string;
  private turnId: string;
  private fireSeq: number = 0;
  private groundedFires: OpenGroundedWriteFire[];
  private readSpinFires: OpenReadSpinFire[];
  private confidenceFires: OpenConfidenceFire[];
  private plainFires: PlainFire[];
  private laterWrites: Array<{path?:string; rawContent?:string; ok:boolean}>;
  private steps: number = 0;
  private assembleMs: number = 0;
  private roundTripMsPerStep: number[];
  private toolExecMsTotal: number = 0;
  private guardOverheadMsTotal: number = 0;
  private totalToolCalls: number = 0;
  private parallelSteps: number = 0;
  private maxParallelCalls: number = 0;

  constructor(engineId: string, turnId: string) {
    this.engineId = engineId;
    this.turnId = turnId;
    this.fireSeq = 0;
    this.groundedFires = [];
    this.readSpinFires = [];
    this.confidenceFires = [];
    this.plainFires = [];
    this.laterWrites = [];
    this.steps = 0;
    this.assembleMs = 0;
    this.roundTripMsPerStep = [];
    this.toolExecMsTotal = 0;
    this.guardOverheadMsTotal = 0;
    this.totalToolCalls = 0;
    this.parallelSteps = 0;
    this.maxParallelCalls = 0;
  }

  recordFire(guardId: GuardId, step: number, blockedCalls: BlockedCallInfo[], fireOverheadMs: number, extra?: {confidenceValue?:number; deferred?:boolean}): string {
    this.fireSeq += 1;
    const fireId = `${this.turnId}:${guardId}:${this.fireSeq}`;
    const event: GuardFireEvent = {
      kind: 'guard_fire',
      id: fireId,
      ts: Date.now(),
      turnId: this.turnId,
      engineId: this.engineId,
      guardId,
      step,
      blockedCalls,
      fireOverheadMs,
      resolution: { label: 'unresolved', observedInTurn: false },
      confidenceValue: extra?.confidenceValue,
    };
    if (guardId === 'grounded-write') {
      // Keep ALL blocked calls (codex FIX 2) — finalize() resolves against
      // every one, not just blockedCalls[0].
      this.groundedFires.push({
        fireId,
        event,
        blockedCalls,
        resolved: false,
      });
    } else if (guardId === 'read-spin') {
      this.readSpinFires.push({ fireId, event, outcome: null, resolved: false });
    } else if (guardId === 'report-confidence') {
      // codex FIX 1: ONLY report-confidence enters the confidence/calibration
      // flow (calibration buckets + averted/recovered labels).
      this.confidenceFires.push({
        fireId,
        event,
        fireStep: step,
        confidenceValue: extra?.confidenceValue ?? 0,
        editOutcomes: [],
        resolved: false,
      });
    } else {
      // codex FIX 1: 'evidence' / 'confidence-escalation' are fire-counting
      // guards in Phase 0 — finalize them as plain fire events (label
      // 'unresolved', observedInTurn=true, NO calibrationBucket). The dashboard
      // already renders them as FIRES + placeholders.
      this.plainFires.push({ fireId, event });
    }
    return fireId;
  }

  recordStep(step: number, info: {roundTripMs:number; toolCallCount:number}): void {
    this.steps += 1;
    this.roundTripMsPerStep.push(info.roundTripMs);
    this.totalToolCalls += info.toolCallCount;
    if (info.toolCallCount > 1) this.parallelSteps += 1;
    if (info.toolCallCount > this.maxParallelCalls) this.maxParallelCalls = info.toolCallCount;
  }

  recordToolResult(step: number, name: string, args: Record<string,unknown>, ok: boolean, rawContent?: string): void {
    const isWrite = name === 'Edit' || name === 'Write' || name === 'MultiEdit';
    if (isWrite) {
      const path = (args.file_path as string | undefined) ?? (args.path as string | undefined);
      const content = rawContent
        ?? (args.content as string | undefined)
        ?? (args.new_string as string | undefined);
      this.laterWrites.push({ path, rawContent: content, ok });
      // Feed the calibration window of every confidence fire still inside the
      // same step or the following 3 steps.
      for (const cf of this.confidenceFires) {
        if (cf.resolved) continue;
        if (step - cf.fireStep >= 0 && step - cf.fireStep <= 3) {
          cf.editOutcomes.push(ok);
        }
      }
    }
  }

  recordReadSpinOutcome(fireId: string, outcome: 'would_have_recovered'|'stalled'|'recovered', extraCostMs?: number): void {
    for (const rf of this.readSpinFires) {
      if (rf.fireId === fireId && !rf.resolved) {
        rf.outcome = outcome;
        rf.resolved = true;
        if (typeof extraCostMs === 'number' && extraCostMs > 0) {
          rf.event.fireOverheadMs += extraCostMs;
        }
        rf.event.resolution = {
          label: outcome,
          observedInTurn: true,
          heuristicVersion: 'v1',
        };
        return;
      }
    }
  }

  recordAssembleMs(ms: number): void {
    this.assembleMs = ms;
  }

  addGuardOverheadMs(ms: number): void {
    this.guardOverheadMsTotal += ms;
  }

  recordToolExecMs(ms: number): void {
    this.toolExecMsTotal += ms;
  }

  finalize(reason: 'done'|'aborted'): {events:GuardFireEvent[]; turn:TurnTelemetryRecord} {
    const events: GuardFireEvent[] = [];

    for (const gf of this.groundedFires) {
      if (reason === 'done') {
        // codex FIX 2: resolve against ALL blocked calls, not just the first.
        gf.event.resolution = deriveGroundedWriteResolutionMulti(
          gf.blockedCalls,
          this.laterWrites,
        );
      }
      events.push(gf.event);
    }

    for (const rf of this.readSpinFires) {
      // Already resolved via recordReadSpinOutcome stays as-is; otherwise it's
      // unresolved (delayed observation never reached a verdict).
      events.push(rf.event);
    }

    for (const cf of this.confidenceFires) {
      if (reason === 'done') {
        const bucket = deriveCalibrationBucket(cf.confidenceValue, cf.editOutcomes);
        cf.event.calibrationBucket = bucket;
        cf.event.resolution = {
          label: cf.editOutcomes.length === 0 ? 'averted' : 'recovered',
          observedInTurn: true,
          detail: bucket,
        };
      }
      events.push(cf.event);
    }

    // codex FIX 1: 'evidence' / 'confidence-escalation' are fire-counting
    // guards — emit them as plain fire events. On 'done' the fire WAS observed
    // this turn (label 'unresolved' / observedInTurn=true) but it never enters
    // the calibration flow, so NO calibrationBucket is set and it can never
    // touch the averted/recovered/highConf* cells. On 'aborted' it keeps the
    // initial unresolved/observedInTurn=false state.
    for (const pf of this.plainFires) {
      if (reason === 'done') {
        pf.event.resolution = { label: 'unresolved', observedInTurn: true };
      }
      events.push(pf.event);
    }

    const turn: TurnTelemetryRecord = {
      kind: 'turn',
      turnId: this.turnId,
      engineId: this.engineId,
      ts: Date.now(),
      steps: this.steps,
      assembleMs: this.assembleMs,
      roundTripMsPerStep: this.roundTripMsPerStep,
      toolExecMsTotal: this.toolExecMsTotal,
      guardOverheadMsTotal: this.guardOverheadMsTotal,
      totalToolCalls: this.totalToolCalls,
      parallelSteps: this.parallelSteps,
      maxParallelCalls: this.maxParallelCalls,
      fires: events.length,
    };

    return { events, turn };
  }
}

/**
 * Construct a fresh per-turn guard-telemetry tracker. One per send()/turn; never share across turns.
 */
// @kern-source: guard-telemetry:468
export function createTurnTracker(engineId: string, turnId: string): GuardTurnTracker {
  return new GuardTurnTracker(engineId, turnId);
}
